mapper.select:
    	/* mapper.mltln.com.erns.coching.MltlnDAO.getList */

    	SELECT B.* FROM (
			SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
				SELECT

				FROM T_MLTLN_MST AA



				ORDER BY AA.CODE ASC
			) A
		)B

	    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

	/* mapper.mltln.com.erns.coching.MltlnDAO.getListVo */

	SELECT B.* FROM (
		SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
			SELECT


			FROM T_MLTLN_MST AA




			ORDER BY AA.code
		) A
    )B

    WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

    	/* com.erns.coching.mltln.mapper.MltlnDAO.load */

    	SELECT

		FROM T_MLTLN_MST AA

			AND AA.CODE 	= #{code	, jdbcType=VARCHAR}
